#include <bits/stdc++.h>
#define lowbit(x) (x&(-x))
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
CI N=5e5+15,MOD=1e9+9;
int n,a[N],sum[N],b[N],dp[N],tr[N];
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
		a=a*a;
		b>>=1;
	}
	return ans;
}
void upd(int x,int k)
{
	for(int i=x;i<=n;i+=lowbit(i))
	{
		tr[i]=(tr[i]+k)%MOD;
	}
}
int qry(int x)
{
	int res=0;
	for(int i=x;i>0;i-=lowbit(i))
	{
		res=(res+tr[i])%MOD;
	}
	return res;
}
signed main(void)
{
	IOS
	memset(tr,0,sizeof(tr));
	cin>>n;
	FOR(i,1,n)
	{
		cin>>a[i];
		sum[i]=sum[i-1]+a[i];
		b[i]=sum[i];
	}
	int tot=n;
	b[++tot]=0;
	sort(b+1,b+tot+1);
	int m=unique(b+1,b+tot+1)-b-1;
	FOR(i,0,n)
	{
		sum[i]=lower_bound(b+1,b+m+1,sum[i])-b;
	}
	upd(sum[0],1);
	FOR(i,1,n)
	{
		dp[i]=qry(sum[i]);
		upd(sum[i],dp[i]);
	}
	cout<<dp[n];
	return false;
}
